import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

public class SecurePathTraversalExample {
    public static void main(String[] args) {
        String userProvidedFileName = "file.txt"; // User input
        String directoryPath = "/path/to/secure/directory/";

        try {
            Path basePath = Paths.get(directoryPath).toRealPath();
            Path resolvedFilePath = basePath.resolve(userProvidedFileName).toRealPath();

            if (!resolvedFilePath.startsWith(basePath)) {
                System.out.println("Invalid file path specified.");
                return;
            }

            byte[] fileData = Files.readAllBytes(resolvedFilePath);
            System.out.println(new String(fileData));
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

